<template>
    <section>
        <div class="col-sm-12 col-md-12 col-lg-12 col-xl-12 float-left p-0" v-if="!isProjectData">
            <div class="heading-border mb-3">
                <h5 class="h5"><span>{{ $t('BulkUploadProjects') }}</span></h5>
            </div>
            <div  v-if="isDuplicate" class="alert alert-danger alert-dismissible">
                    <a href="javascript:;" class="close" data-dismiss="alert" aria-label="close"> x </a>
                    <label>{{$t('Find Duplicate Project Name')}}: {{ $t(DuplicateName) }}</label>
            </div>
            <div class="col-sm-12 col-md-12 col-lg-12 col-xl-12 float-left p-0">
                <div class="listing">
                        <div class="table-responsive" id="divProjectList" style="overflow: visible;">
                                <table id="tblProjectList" class="table table-bordered dt-responsive nowrap mt-0">
                                    <thead class="thead-bg">
                                        <tr>
                                            <th style="width: 12%">
                                                <span>{{ $t('ProjectName') }}</span>
                                            </th>
                                            <th style="width: 10%">
                                                <span>{{ $t('ProjectRate') }}</span>
                                            </th>
                                            <th style="width: 13%">
                                                <span>{{ $t('ProjectHours') }}</span>
                                            </th>
                                            <th style="width: 15%">
                                                <span>{{ $t('PlanStartDate') }}</span>
                                            </th>
                                            <th style="width: 15%">
                                                <span>{{ $t('PlanEndDate') }}</span>
                                            </th>
                                            <th style="width: 15%">
                                                <span>{{ $t('IndustryType') }}</span>
                                            </th>
                                            <th style="width: 15%">
                                                <span>{{ $t('Template') }}</span>
                                            </th>
                                            <th style="width: 2%" class="text-center">
                                                <span>{{ $t('Action') }}</span>
                                            </th>
                                        </tr>
                                    </thead>                                  
                                    <tbody class="gridRowsBody">
                                        <tr v-if="expListing==null">
                                            <td colspan="8" class="text-center text-danger no-record">
                                                {{ $t('NoRecordfound') }}
                                            </td>
                                        </tr>   
                                                    
                                        <tr :class="'seletedrow'+index" v-for="(item,index) in expListing" :key="index">                                                                                   
                                            <td>
                                                <Field :rules="{'required': true}" :name="'projectName'+index" v-slot="{errors}">
                                                    <input v-model="item.projectName" :name="'projectName'+index" type="text"
                                                        v-bind:class="{'form-control' : true,'is-invalid': errors[0]}"  />
                                                        <span v-if="errors[0]"  :name="'projectName'+index" class="invalid-feedback">{{$t('Project Name is Required.')}}</span>                                          
                                                </Field> 
                                            </td>
                                            <td>
                                                <Field :rules="{'required': true}" :name="'ProjectRate'+index" v-slot="{errors}">
                                                    <input v-model="item.perHourRate"
                                                     :name="'ProjectRate'+index" 
                                                     @keypress="validateInput($event)"
                                                    @input="formatInput($event, member)"
                                                    @paste="handlePaste($event, member)"
                                                       type="text"
                                                        v-bind:class="{'form-control' : true,'is-invalid': errors[0]}"  />
                                                        <span v-if="errors[0]"  :name="'ProjectRate'+index" class="invalid-feedback">{{$t('Project Rate is Required.')}}</span>                                          
                                                </Field> 
                                            </td>
                                            <td>
                                                <Field :rules="{'required': true}" :name="'ProjectHours'+index" v-slot="{errors}">
                                                    <input v-model="item.displayProjectHrs" :name="'ProjectHours'+index" type="text"
                                                    @keypress="validateInput($event)"
                                                    @input="formatInput($event, member)"
                                                    @paste="handlePaste($event, member)"
                                                        v-bind:class="{'form-control' : true,'is-invalid': errors[0]}"  />
                                                        <span v-if="errors[0]"  :name="'ProjectHours'+index" class="invalid-feedback">{{$t('Project Hours is Required.')}}</span>                                          
                                                </Field> 
                                            </td>
                                            <td style="overflow:visible!important;">
                                                <div class="input-group"> 
                                                    <Field  :name="'PlanStartDate'+index" v-slot="{ errors,changed}">                                              
                                                        <v-date-picker :name="'PlanStartDate'+index" :minute-increment="5" class="input-group" v-model="item.planStartDate"  @update:modelValue="getStartDateHandler(item, index, changed)" :min-date="startDate" >
                                                            <template v-slot="{ inputValue,  togglePopover}">
                                                                <input  v-bind:class="{ 'form-control': true, 'is-invalid': errors[0]}"
                                                                     :value="inputValue"  placeholder="HH:MM:YYYY" />
                                                                <div @click="togglePopover()" class="input-group-append">
                                                                <span class="input-group-text"> <em class="fa fa-calendar"></em></span>
                                                               </div>
                                                            </template>
                                                        </v-date-picker>  
                                                    </Field>
                                                </div>
                                            </td>
                                            <td style="overflow:visible!important;">                                                                
                                                <div class="input-group">        
                                                    <Field  :name="'PlanEndDate'+index" v-slot="{ errors,changed}">                                              
                                                        <v-date-picker :name="'PlanEndDate'+index" :minute-increment="5" class="input-group" v-model="item.planEndDate"  @update:modelValue="changed" :min-date="getMinEndDate(item)" >
                                                            <template v-slot="{ inputValue,  togglePopover}">
                                                                <input  v-bind:class="{ 'form-control': true, 'is-invalid': errors[0]}"
                                                                     :value="inputValue"  placeholder="HH:MM:YYYY" />
                                                                <div @click="togglePopover()" class="input-group-append">
                                                                <span class="input-group-text"> <em class="fa fa-calendar"></em></span>
                                                               </div>
                                                            </template>
                                                        </v-date-picker>  
                                                    </Field>
                                                </div>
                                            </td>
                                            <td class="pro">
                                                <div class="input-group">        
                                                    <Field  :rules="{ 'required': true }" :name="'IndustryType'+index" v-slot="{ errors }">
                                                        <select v-model="item.IndustryTypeId"    :name="'IndustryType'+index" @change="GetTemplateListData(item,index)"
                                                            v-bind:class="{'form-control' : true,'is-invalid':errors[0]}">
                                                            <option value="">Please Select Industry Type</option>
                                                            <option v-for="(option,index1) in IndustryTypeTemplate" :key="index1" :value="option.id">{{ option.name }}</option>
                                                        </select> 
                                                        <span v-if="errors[0]"   :name="'IndustryType'+index" class="invalid-feedback">{{$t('ProjectValidate')}}</span>                                              
                                                    </Field> 
                                                </div>                             
                                            </td>
                                            <td class="pro">
                                                <Field :rules="{ 'required': true }" :name="'TemplateType'+index" v-slot="{ errors }">
                                                    <select v-model="item.TemplateId" :name="'TemplateType'+index" v-bind:key="item.IndustryTypeId"
                                                        v-bind:class="{'form-control' : true,'is-invalid':errors[0]}">
                                                        <option value="">Please Select Template</option>
                                                        <option v-for="(option,index2) in item.TemplateData" :key="index2" :value="option.id">{{ option.name }}</option>
                                                    </select> 
                                                    <span v-if="errors[0]"   :name="'TemplateType'+index" class="invalid-feedback">{{$t('ProjectValidate')}}</span>                                              
                                                </Field> 
                                                                                        
                                            </td> 
                                            <td class="text-center">
                                                <span :id="'deleteProject'+index" class="delete single-action" title="Delete" :value="index">
                                                    <em class="fa fa-trash-o text-danger" @click="DeleteProject(index)"></em>
                                                </span>
                                            </td>
                                        </tr>
                                    </tbody>
                                </table>
                            </div>
                        </div>
                    <div>
                </div>
                <div class="col-sm-12 col-md-12 col-lg-12 col-xl-12 float-left mt-3 p-0">
                    <div class="form-group">
                        <div class="search-btm-btn text-right">                           
                            <a id="aSubmit" @click="OnSubmit" class="btn btn-success formbtn text-white mr-2" title="Submit"><i class="fa fa-save pr-2"></i>{{ $t('Submit') }}</a>                           
                            <a id="aCancel" @click="OnCanel" class="btn btn-danger formbtn" title="Cancel"><i class="fa fa-close pr-2"></i>{{ $t('Cancel') }}</a>
                        </div>
                    </div>
                </div>
            </div>
        </div>
        <div id="divBulkProjects" class="col-sm-12 col-md-12 col-lg-12 col-xl-12 p-0 float-left" v-if="isProjectData">
            <div class="col-sm-12 col-md-12 col-lg-12 col-xl-12 float-left p-0">
                <div class="alert alert-success alert-dismissible">
                    <a href="javascript:;" class="close" data-dismiss="alert" aria-label="close"> x </a>
                    <label>{{$t('RecordsSavedSuccessfully')}}.</label>
                </div>
            </div>
            <div class="col-sm-12 col-md-12 col-lg-12 col-xl-12 float-left p-0">
                <div class="table-responsive tableborder">
                    <table id="tblProjectList" class="table-sorting table table-bordered mb-0">
                        <thead class="thead-light">
                            <tr>
                                <th style="width: 12%">
                                    <span>{{ $t('ProjectName') }}</span>
                                </th>
                                <th style="width: 10%">
                                    <span>{{ $t('ProjectRate') }}</span>
                                </th>
                                <th style="width: 13%">
                                    <span>{{ $t('ProjectHours') }}</span>
                                </th>
                                <th style="width: 15%">
                                    <span>{{ $t('PlanStartDate') }}</span>
                                </th>
                                <th style="width: 15%">
                                    <span>{{ $t('PlanEndDate') }}</span>
                                </th> 
                                <th style="width: 15%">
                                    <span>{{ $t('IndustryType') }}</span>
                                </th>
                                <th style="width: 15%">
                                    <span>{{ $t('Template') }}</span>
                                </th>                               
                            </tr>
                        </thead>
                        <tbody>                          
                            <tr v-for="(item,index) in ProjectData" :key="index">
                                <th>
                                    <span>{{ item.project_name }}</span>
                                </th>
                                <th>
                                    <span>{{ convertDecimalValueInFormat(item.base_rate) }}</span>
                                </th>
                                <th>
                                    <span>{{ item.estimated_hours }}</span>
                                </th>
                                <th>
                                    <span>{{ $options.filters.formatDate(item.planned_start_date) }}</span>
                                </th>
                                <th>
                                    <span>{{ $options.filters.formatDate(item.planned_end_date) }}</span>
                                </th>  
                                <th style="width: 15%">
                                    <span>{{ item.Industry_Type}}</span>
                                </th>
                                <th style="width: 15%">
                                    <span>{{ item.Template_Name }}</span>
                                </th>
                            </tr>
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    </section>
</template>
<script>
import DataService from '../../services/DataService'
export default {
    props: {
        path: null
    },
    data() {
        return {
            expListing:[],
            isDuplicate:false,
            isProjectData:false,
            ProjectData:[],
            DuplicateName:'',
            IndustryTypeTemplate:[],
            DdlTemplateData:[], 
            startDate:'',
            endDate:'',
            companyCurrency:'',
            projectCurrency:'',
        }
    },
    created:async function(){ 
        //debugger
        var ths=this;
        ths.startDate=new Date();
        ths.endDate = new Date();
        ths.endDate.setDate(ths.endDate.getDate() + 7);
        ths.userDateFormat=ths.GetUserInfo.DateFormat;
        ths.companyCurrency=ths.GetUserInfo.Currency.replace(/[()]/g, '');
        ths.GetCurrency();
        await ths.GetIndustryType();
        setTimeout( function () {
              ths.ProjectDetails();   
        }, 500);
        
    },
    methods:{
        GetCurrency(){            
            var url = `id=&moduleName=PROJECT&type=CURRENCY_FOR_PROJECT&search=&refId=`;
            DataService.GetDDLData(url).then((response)=>{ 
                if (response.status == 200) {
                    if (response.data.DATA != undefined || response.data.DATA != null) {
                        if (response.data.DATA.length > 0) { 
                            this.projectCurrency = response.data.DATA.filter(x => x.first_value == this.companyCurrency)                
                        }
                    }
                }
            })
        },
        validateInput(event) {
      const char = String.fromCharCode(event.which || event.keyCode);
      const input = event.target;
      const value = input.value || '';
      const selectionStart = input.selectionStart || 0;
      const selectionEnd = input.selectionEnd || 0;
      
      // Allow backspace, delete, tab, escape, enter, arrow keys, home, end
      if ([8, 9, 27, 13, 46, 37, 38, 39, 40, 35, 36].indexOf(event.keyCode) !== -1 ||
          // Allow Ctrl+A, Ctrl+C, Ctrl+V, Ctrl+X
          (event.keyCode === 65 && event.ctrlKey === true) ||
          (event.keyCode === 67 && event.ctrlKey === true) ||
          (event.keyCode === 86 && event.ctrlKey === true) ||
          (event.keyCode === 88 && event.ctrlKey === true)) {
        return;
      }
      
      // Allow only numbers and decimal point
      if (!/[0-9.]/.test(char)) {
        event.preventDefault();
        return;
      }
      
      // Get the text that will result from this keypress
      const textBefore = value.substring(0, selectionStart);
      const textAfter = value.substring(selectionEnd);
      const newValue = textBefore + char + textAfter;
      
      // Check if decimal point already exists
      if (char === '.' && value.indexOf('.') !== -1) {
        event.preventDefault();
        return;
      }
      
      // Validate format: max 5 digits before decimal, max 2 after
      const parts = newValue.split('.');
      const beforeDecimal = parts[0] || '';
      const afterDecimal = parts[1] || '';
      
      // Prevent 6th digit before decimal
      if (beforeDecimal.length > 5) {
        event.preventDefault();
        return;
      }
      
      // Prevent 3rd digit after decimal
      if (afterDecimal.length > 2) {
        event.preventDefault();
        return;
      }
      
      this.isValid = true;
    },
    formatInput(event, member) {
      const input = event.target;
      let value = input.value;
      
      if (value === '' || value === null || value === undefined) {
        member.ratePerHour = '';
        this.isValid = true;
        return;
      }
      
      // Convert to string
      value = String(value);
      
      // Remove any non-numeric characters except decimal point
      value = value.replace(/[^0-9.]/g, '');
      
      // Handle multiple decimal points - keep only the first one
      const decimalIndex = value.indexOf('.');
      if (decimalIndex !== -1) {
        const before = value.substring(0, decimalIndex);
        const after = value.substring(decimalIndex + 1).replace(/\./g, '');
        value = before + '.' + after;
      }
      
      // Split by decimal point
      const parts = value.split('.');
      let beforeDecimal = parts[0] || '';
      let afterDecimal = parts[1] || '';
      
      // Limit to 5 digits before decimal - remove 6th digit or more
      if (beforeDecimal.length > 5) {
        beforeDecimal = beforeDecimal.substring(0, 5);
      }
      
      // Limit to 2 digits after decimal - remove 3rd digit or more
      if (afterDecimal.length > 2) {
        afterDecimal = afterDecimal.substring(0, 2);
      }
      
      // Reconstruct the value
      let formattedValue = beforeDecimal;
      const hadDecimal = value.indexOf('.') !== -1;
      if (hadDecimal) {
        // If original value had decimal point, include it
        formattedValue = beforeDecimal + '.' + afterDecimal;
      }
      
      // Update the model value (v-model will update the input)
      if (formattedValue === '' || formattedValue === '.') {
        member.ratePerHour = '';
      } else {
        member.ratePerHour = formattedValue;
      }
      
      // Validate - ensure format is correct (max 5 before, max 2 after)
      this.isValid = beforeDecimal.length <= 5 && afterDecimal.length <= 2;
    },
    handlePaste(event, member) {
      event.preventDefault();
      const pastedText = (event.clipboardData || window.clipboardData).getData('text');
      
      if (!pastedText) return;
      
      // Process pasted text through formatInput logic
      let value = String(pastedText);
      
      // Remove any non-numeric characters except decimal point
      value = value.replace(/[^0-9.]/g, '');
      
      // Handle multiple decimal points - keep only the first one
      const decimalIndex = value.indexOf('.');
      if (decimalIndex !== -1) {
        const before = value.substring(0, decimalIndex);
        const after = value.substring(decimalIndex + 1).replace(/\./g, '');
        value = before + '.' + after;
      }
      
      // Split by decimal point
      const parts = value.split('.');
      let beforeDecimal = parts[0] || '';
      let afterDecimal = parts[1] || '';
      
      // Limit to 5 digits before decimal
      if (beforeDecimal.length > 5) {
        beforeDecimal = beforeDecimal.substring(0, 5);
      }
      
      // Limit to 2 digits after decimal
      if (afterDecimal.length > 2) {
        afterDecimal = afterDecimal.substring(0, 2);
      }
      
      // Reconstruct the value
      let formattedValue = beforeDecimal;
      if (value.indexOf('.') !== -1 && afterDecimal.length > 0) {
        formattedValue = beforeDecimal + '.' + afterDecimal;
      }
      
      // Update the model value
      member.ratePerHour = formattedValue === '' ? '' : formattedValue;
      this.isValid = beforeDecimal.length <= 5 && afterDecimal.length <= 2;
    },
        convertDecimalValueInFormat: function (value) {            
            try {
                value = parseFloat(value, 10);
                value = value.toFixed(2);
                value = parseFloat(value, 10);
                value = value.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
                return value;
            } catch (ex) {
                return value;
            }
        },
        getStartDateHandler(item, index, changed) {
            // Return a function that captures item, index, and changed in closure
            return (value) => {
                // Call the form validation callback first
                if (changed && typeof changed === 'function') {
                    changed(value);
                }
                
                // Then handle the date change logic
                this.onStartDateChange(value, item, index);
            };
        },
        onStartDateChange(value, item, index) {
            // When start date changes, automatically set end date to 7 days ahead
            if (!value) return;
            
            let startDateObj;
            
            // Handle Date object (most common case from v-date-picker)
            if (value instanceof Date) {
                startDateObj = new Date(value);
            } 
            // Handle moment object (if formatDate returns moment)
            else if (value && typeof value === 'object' && value._isAMomentObject) {
                startDateObj = value.toDate();
            }
            // Handle string (formatted date)
            else if (typeof value === 'string') {
                startDateObj = new Date(value);
                // If parsing fails, try alternative formats
                if (isNaN(startDateObj.getTime())) {
                    // Try replacing slashes with dashes
                    const dateStr = value.replace(/\//g, '-');
                    startDateObj = new Date(dateStr);
                }
            } else {
                return;
            }
            
            // Validate the date
            if (!startDateObj || isNaN(startDateObj.getTime())) {
                return;
            }
            
            // Add 7 days to start date
            const endDateObj = new Date(startDateObj);
            endDateObj.setDate(endDateObj.getDate() + 7);
            
            // Format and set the end date using the same formatDate filter
            this.$set(item, 'planEndDate', this.$options.filters.formatDate(endDateObj));
        },
        getMinEndDate(item) {
            
            // Return the start date as minimum end date, or fallback to startDate
            if (item.planStartDate) {
                let startDateObj;
                
                // Handle Date object
                if (item.planStartDate instanceof Date) {
                    startDateObj = new Date(item.planStartDate);
                }
                // Handle moment object
                else if (item.planStartDate && typeof item.planStartDate === 'object' && item.planStartDate._isAMomentObject) {
                    startDateObj = item.planStartDate.toDate();
                }
                // Handle string
                else if (typeof item.planStartDate === 'string') {
                    startDateObj = new Date(item.planStartDate);
                    if (isNaN(startDateObj.getTime())) {
                        const dateStr = item.planStartDate.replace(/\//g, '-');
                        startDateObj = new Date(dateStr);
                    }
                }
                
                // Return valid date or fallback
                if (startDateObj && !isNaN(startDateObj.getTime())) {
                    const endDateObj = new Date(startDateObj);
                    endDateObj.setDate(endDateObj.getDate() + 7);
                    this.$set(item, 'planEndDate', this.$options.filters.formatDate(endDateObj));
                    return endDateObj;
                }
            }
            return this.startDate;
        },
        async GetIndustryType(){  
            DataService.GetTemplateList().then((response)=>{ 
                if (response.data.result.DATA.length>0) {                    
                    this.IndustryTypeTemplate=response.data.result.DATA;                    
                }
            })
        },        
        async ProjectDetails() { 
            var vm = this;
            var param = `filepath=${vm.path}`;
            vm.isLoading = true;               
            await DataService.BulkUploadProject(param).then(async (response) => {
                vm.isLoading = false;
                if (response.data.msgFor === "success") {                    
                    const data = response.data;
                    vm.expListing = data.listing;
                    const industryTypeMap = new Map(vm.IndustryTypeTemplate.map(industry => [industry.name, industry.id]));
                    for (let [index, item] of vm.expListing.entries()) {
                        if (industryTypeMap.has(item.industryType)) {
                            item.planStartDate = vm.$options.filters.formatDate(new Date());
                            item.planEndDate = vm.$options.filters.formatDate(vm.endDate);
                            item.IndustryTypeId = industryTypeMap.get(item.industryType);
                            vm.$set(item, 'TemplateData', []);
                            vm.$set(item, 'TemplateId', '');
                            await vm.GetTemplateListData(item, index);  
                        }
                    }
                }
            });  
        },
        async GetTemplateListData(itm, index) {   
            itm.TemplateData = [];                
            var url = `IndustryTypeId=${itm.IndustryTypeId}`; 

            try {
                const response = await DataService.GetTemplateListData(url); 
                
                if (response.data.result.DATA.length > 0) {    
                    var GetTemplateList = response.data.result.DATA;               
                    const templateMap = new Map(GetTemplateList.map(template => [template.name, template.id]));                
                    this.$set(itm, 'TemplateData', GetTemplateList);
                   this.$set(itm, 'TemplateId', templateMap.get(itm.templateName) || '');
                              
                } 
            } catch (err) {
                console.error("Error fetching template list:", err);
            }
        },
        OnCanel:function(){
            this.$parent.Close();
        },
        DeleteProject(index) {
            if (index > -1 && index < this.expListing.length) {
                this.expListing.splice(index, 1);
            } else {
                console.error('Invalid index');
            }
        },
        OnSubmit:function(){  
           // debugger
            var vm = this;
            vm.isLoading=true;
            var expListing=[];
            vm.expListing.forEach((item)=>{
                let obj={
                    projectName:item.projectName.trim(),
                    displayProjectHrs:item.displayProjectHrs,
                    perHourRate:item.perHourRate,
                    planStartDate:item.planStartDate,
                    planEndDate:item.planEndDate,
                    IndustryTypeId:item.IndustryTypeId,
                    TemplateId:item.TemplateId,
                    estimatedCost:parseFloat(item.perHourRate).toFixed(2) * parseFloat(item.displayProjectHrs).toFixed(2),
                    currencyId:vm.projectCurrency[0].value
                }
                expListing.push(obj);
            })
            var postJSON = {
                data: expListing               
            };
            var objectPostString = JSON.stringify(postJSON);
            DataService.SaveBulkUploadProject(objectPostString).then(function (response) { 
            vm.isLoading = false;            
            const result = response.data.result; 
            var DuplicateArray= result.IsDuplicate.length>0?true:false;                          
                if (result != null) {  
                    if(DuplicateArray) {
                          vm.isDuplicate=true;
                          vm.DuplicateName='';
                        result.IsDuplicate.forEach((item)=>{
                            vm.DuplicateName +=result.IsDuplicate.length > 1 ? item.PROJECTNAME + ',' :  item.PROJECTNAME ;
                        })  
                        return;                  
                        
                    }                
                    else  if (result && result.ProjectData !=[]) {                                              
                        vm.$parent.FetchData();   
                        vm.isDuplicate=false;              
                        vm.isProjectData=true;
                        vm.ProjectData=result.ProjectData;                    
                        
                    }
                }
                else if(response.data.status=='Failure'){
                    vm.ShowAlert(vm.$t('UnknownErrorOccur'), "failure", true, vm.$t("Alert"));
                }
            });
        }
    }
}
</script>